    long long operations = 0;
    for (int i = 25; i >= 0; --i) {
        if (counts[i] == 0) continue;
        if (i == 0) break; // 'a' doesn't need any operations

        // The number of operations needed to turn 'a'+i into 'a' is (26 - i) % 26
        // But since we process from 'z' to 'a', each operation is applied once per character
        operations += (26 - i) % 26;
